def check_permission(user: dict, resource: dict, action: str) -> dict:
    # Check revoked scopes first
    for revoked in user.get("revoked_scopes", []):
        if revoked["resource_id"] == resource["id"] and revoked["action"] == action:
            return {"allowed": False, "reason": "revoked"}

    # Check admin role
    if user.get("role") == "admin":
        return {"allowed": True, "reason": "admin"}

    # Check owner
    if user.get("id") == resource.get("owner_id"):
        return {"allowed": True, "reason": "owner"}

    # Check reviewer
    if user.get("role") == "reviewer":
        if action == "read":
            return {"allowed": True, "reason": "reviewer_read"}
        else:
            return {"allowed": False, "reason": "default_deny"}

    # Check member
    if user.get("role") == "member":
        if action in ("read", "write") and resource.get("team_id") in user.get("teams", []):
            return {"allowed": True, "reason": "member_team"}

    # Default deny
    return {"allowed": False, "reason": "default_deny"}
